#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>

typedef struct Node {
    long long key;
    long long val;
    struct Node* next;
} Node;

#define MOD 262144
static Node* table[MOD];

static unsigned int hash_func(long long x) {
    return (unsigned int)((x ^ (x >> 32)) & (MOD - 1));
}

static void clear_table() {
    for (int i = 0; i < MOD; ++i) {
        Node* cur = table[i];
        while (cur) {
            Node* tmp = cur;
            cur = cur->next;
            free(tmp);
        }
        table[i] = NULL;
    }
}

static long long get(long long key) {
    unsigned int h = hash_func(key);
    Node* cur = table[h];
    while (cur) {
        if (cur->key == key) return cur->val;
        cur = cur->next;
    }
    return 0LL;
}

static void inc(long long key) {
    unsigned int h = hash_func(key);
    Node* cur = table[h];
    while (cur) {
        if (cur->key == key) { cur->val++; return; }
        cur = cur->next;
    }
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->key = key;
    nd->val = 1;
    nd->next = table[h];
    table[h] = nd;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; long long k; scanf("%d %lld", &n, &k);
        clear_table();
        inc(0LL); // prefix sum 0 occurs once before start
        long long pref = 0, ans = 0;
        for (int i = 0; i < n; ++i) {
            long long x; scanf("%lld", &x);
            pref += x;
            ans += get(pref - k);
            inc(pref);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

