    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int n; long long k; cin>>n>>k;
        unordered_map<long long,long long> cnt;
        cnt.reserve(n*2);
        cnt[0]=1;
        long long pref=0, ans=0;
        for(int i=0;i<n;++i){
            long long x; cin>>x;
            pref+=x;
            ans+=cnt[pref - k];
            ++cnt[pref];
        }
        cout<<ans<<"\n";
    }
    return 0;
}

